import bisect


class Skiplist:
    def __init__(self):
        self.data = []
    def search(self, target):
        i = bisect.bisect_left(self.data, target)
        return i < len(self.data) and self.data[i] == target
    def add(self, num):
        bisect.insort(self.data, num)
    def erase(self, num):
        i = bisect.bisect_left(self.data, num)
        if i < len(self.data) and self.data[i] == num:
            self.data.pop(i)
            return True
        return False

