var Skiplist = function() {
    this.data = [];
};
Skiplist.prototype._lower = function(target) {
    let lo = 0, hi = this.data.length;
    while (lo < hi) {
        const mid = (lo + hi) >> 1;
        if (this.data[mid] < target) lo = mid + 1; else hi = mid;
    }
    return lo;
};
Skiplist.prototype.search = function(target) {
    const i = this._lower(target);
    return i < this.data.length && this.data[i] === target;
};
Skiplist.prototype.add = function(num) {
    const i = this._lower(num);
    this.data.splice(i, 0, num);
};
Skiplist.prototype.erase = function(num) {
    const i = this._lower(num);
    if (i < this.data.length && this.data[i] === num) {
        this.data.splice(i, 1);
        return true;
    }
    return false;
};
